    // E_count[i] stores the count of even numbers in nums[0...i]
    const E_count = new Array(N).fill(0);
    for (let i = 0; i < N; i++) {
        const isEven = nums[i] % 2 === 0 ? 1 : 0;
        const previousCount = i > 0 ? E_count[i - 1] : 0;
        E_count[i] = previousCount + isEven;
    }

    /**
     * Finds the largest index j (0 <= j < N) such that nums[j] <= X.
     * Returns -1 if all elements are greater than X.
     */
    function findLastLE(X) {
        let low = 0;
        let high = N - 1;
        let ans = -1;

        while (low <= high) {
            // Use Math.floor for integer division
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= X) {
                ans = mid; // Candidate found
                low = mid + 1; // Try to find a larger index
            } else {
                high = mid - 1; // Too large
            }
        }
        return ans;
    }

    const results = [];

    for (let i = 0; i < Q; i++) {
        const [L, R, K] = queries[i];

        // Function to check if the k-th smallest remaining even number is <= X
        const check = (X) => {
            if (X < 2) return false;

            // 1. Find r', the index of the last element in nums <= X
            const r_prime = findLastLE(X);

            // 2. Determine the effective upper bound for counting removals
            const r_eff = Math.min(R, r_prime);

            // If the effective upper bound is before the start index L, no elements in the range [L, R] are <= X.
            if (r_eff < L) {
                // C(X) = 0
                // Count of remaining = X/2 - 0
                return Math.floor(X / 2) >= K;
            }

            // 3. Calculate C(X): count of even numbers in nums[L..r_eff]
            let removedCount;
            if (L === 0) {
                removedCount = E_count[r_eff];
            } else {
                removedCount = E_count[r_eff] - E_count[L - 1];
            }

            // Total count of evens <= X is X/2
            const totalEvens = Math.floor(X / 2);
            const remainingCount = totalEvens - removedCount;

            return remainingCount >= K;
        };

        // Step 3: Binary Search for the minimum X satisfying check(X) >= K

        // Lower bound: The smallest possible even number is 2.
        let low = 2;

        // Upper bound: If nothing is removed, the K-th number is 2K. Max K=10^9, so 2*10^9.
        // We use a slightly higher bound to be safe.
        let high = 3000000000; 
        let ans_X = high;

        while (low <= high) {
            // Use Math.floor for integer division
            const mid = Math.floor((low + high) / 2);

            if (check(mid)) {
                ans_X = mid; // Potential answer
                high = mid - 1; // Try smaller
            } else {
                low = mid + 1; // Need larger X
            }
        }

        results.push(ans_X);
    }

    return results;
}
